module RefModule (
    input wire clk,
    input wire signal_in,
    output reg zero_cross
);
    reg obf_signal_prev;

    always @(posedge clk) begin
        zero_cross <= (signal_in ^ obf_signal_prev) && obf_signal_prev != signal_in;
        obf_signal_prev <= signal_in;
    end
endmodule
